let cachedSlots = null;

export function getHomeReferenceSlots() {
  if (cachedSlots) {
    return cachedSlots;
  }

  const bytes = decodeBase64(SLOT_DATA_BASE64);
  const slots = new Array(SLOT_COUNT);
  let offset = 0;

  for (let index = 0; index < SLOT_COUNT; index += 1) {
    const x = readUInt16(bytes, offset) / COORDINATE_SCALE;
    offset += 2;
    const y = readUInt16(bytes, offset) / COORDINATE_SCALE;
    offset += 2;
    const alpha = bytes[offset] / 255;
    offset += 1;
    const radiusScale = bytes[offset] / 255;
    offset += 1;
    const glowStrength = bytes[offset] / 255;
    offset += 1;
    const sharpness = bytes[offset] / 255;
    offset += 1;
    const sparkle = bytes[offset] / 255;
    offset += 1;
    const palette = SLOT_PALETTES[bytes[offset]] ?? SLOT_PALETTES[0];
    offset += 1;

    slots[index] = {
      x,
      y,
      homeColor: palette.fill,
      homeCoreColor: palette.core,
      homeHaloColor: palette.halo,
      homeAlpha: alpha,
      homeRadiusScale: radiusScale,
      homeGlowStrength: glowStrength,
      homeSharpness: sharpness,
      homeSparkle: sparkle,
    };
  }

  cachedSlots = slots;
  return slots;
}

function decodeBase64(value) {
  if (typeof atob === 'function') {
    const binary = atob(value);
    return Uint8Array.from(binary, (character) => character.charCodeAt(0));
  }
  return Uint8Array.from(Buffer.from(value, 'base64'));
}

function readUInt16(bytes, offset) {
  return bytes[offset] | (bytes[offset + 1] << 8);
}
